// Initialize the Office Add-in Runtime
Office.onReady(function (info) {
    if (info.host === Office.HostType.Excel) {
        // Ensure the DOM has fully loaded before trying to bind elements
        document.addEventListener("DOMContentLoaded", function () {
            initializeAddIn();
        });
    }
});

/**
 * Binds all interface click events dynamically so that the Webpack/Parcel 
 * bundler does not hide them from inline HTML tags.
 */
function initializeAddIn() {
    // 1. Setup Settings Panel Open/Close Button
    const settingsBtn = document.getElementById("settingsBtn");
    if (settingsBtn) {
        settingsBtn.addEventListener("click", toggleSettingsMenu);
    }

    // 2. Setup the Worksheet Tabs Toggle (Show/Hide)
    const tabsToggle = document.getElementById("toggle-sheet-tabs");
    if (tabsToggle) {
        // Sync the toggle state with Excel's current actual settings on load
        syncInitialTabsState(tabsToggle);

        // Bind click event to Excel API to execute show/hide when toggled
        tabsToggle.addEventListener("change", function () {
            toggleExcelSheetTabs(tabsToggle.checked);
        });
    }
}

/**
 * Opens or closes the settings container interface panel
 */
function toggleSettingsMenu() {
    const menu = document.getElementById("settingsMenu");
    if (menu) {
        menu.classList.toggle("hidden");
    }
}

/**
 * Checks Excel's current visual state on startup and ensures the settings checkbox 
 * matches (so it isn't "checked" when tabs are actually hidden, or vice versa).
 */
async function syncInitialTabsState(checkboxElement) {
    try {
        await Excel.run(async (context) => {
            const activeWindow = context.workbook.getActiveWindow();
            activeWindow.load("showWorkbookTabs");
            await context.sync();
            
            // Apply current Excel state to HTML checkbox
            checkboxElement.checked = activeWindow.showWorkbookTabs;
        });
    } catch (error) {
        console.error("Could not sync Excel window state with setting toggle: ", error);
    }
}

/**
 * Interacts with the Excel Desktop Window API to toggles sheet tab visibility
 * @param {boolean} isVisible - True to show worksheet tabs, False to hide them
 */
async function toggleExcelSheetTabs(isVisible) {
    try {
        // Desktop platform check - modifying sheet tab visibility is only supported in desktop clients
        if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) {
            await Excel.run(async (context) => {
                const activeWindow = context.workbook.getActiveWindow();
                activeWindow.showWorkbookTabs = isVisible;
                await context.sync();
            });
        } else {
            console.warn("The 'ExcelApiDesktop' layout requirements are not supported on this device's runtime.");
        }
    } catch (error) {
        console.error("Failed executing sheet tab visibility action: ", error);
    }
}